async function getIssueDetail(issueId:string){
    const ret = await getIssueInfo({"username":process.env.JIRA_USER_RN as string}, issueId);

    const permissions = await getRnRequestPermissionByIDCIssueId(ret.id);

    console.log(ret);
    console.log(permissions);
}

async function getRequestPermissions(id:string){
    const ret = await getRnRequestPermissionByIDCIssueId(id);
    console.log(ret);
}

async function updateRequestPermissionTime(id:string){
    const ret = await getPendingRnRequestPermissionByIDCIssueId(id);
    for(const requestPermission of ret){
        console.log(requestPermission);
        if(requestPermission.rn_event_id != null && requestPermission.rn_event_id != "") {
            await updateRnRequestPermissionTime(requestPermission.rn_event_id, (new Date()).toISOString());
        }
    }
}

async function getIssueByAlarmId(alarmId: string){
    const issueList = await getIssueListByAlarmId(alarmId);
    console.log(JSON.stringify(issueList));
}


async function getCustomField(){
    const data = await getIssueFields();
    console.log(JSON.stringify(data));
}

export const alarmRecovery = async (alarmId:string) => {
    const ret: any[] = [];
    if(!alarmId && alarmId != ""){
        return ret;
    }

    try {
        const issueList = await getIssueListByAlarmId(alarmId);

        if (issueList.total > 0){
            for(const issue of issueList.issues) {
                if(issue.fields.status.name == 'PBD-CANCELED'){
                    continue;
                }

                const data:any = {
                    "status": "PBD-CANCELED" ,
                    "comment": "Alarm recovery"
                };

                await updateIssue({username:'alarm-prod'}, issue.id, data, false);
                const name = issue.fields.assignee ? issue.fields.assignee.name : ""
                await sendAlarmAutoRecoveryMessage(issue, name);

                ret.push(issue.id);
            }
        }

        return ret;
    } catch (error: any) {
        console.log(error);
        return ret;
    }
};

async function refreshAutoRecovery(alarmIds:string[]){
    let recoveriedIds:any[] = [];

    // 🔥 5 行多线程替换！（删除原 for 循环）
    const limit = pLimit(5); // 并发 5 个，JIRA 最稳定
    const promises = alarmIds.map(alarmId =>
        limit(async () => await alarmRecovery(alarmId))
    );
    const results = await Promise.all(promises);
    results.forEach(issueIds => recoveriedIds.push(...issueIds));

    console.log("🎉 refreshAutoRecovery finished");
    console.log(JSON.stringify(recoveriedIds));
}

async function getAlarmIssudIds(alarmId:string){
    const ret:any[] = [];
    const issueList = await getIssueListByAlarmId(alarmId);
    if (issueList.total > 0){
        for(const issue of issueList.issues) {
            if(issue.fields.status.name == 'PBD-CANCELED' && issue.fields.issuetype.id !== IssueTypeEnum.Alarm){
                ret.push(issue.id);
            }
        }
    }
    return ret;
}

async function getAutoRecoveryIds(alarmIds:string[]){
    let recoveriedIds:any[] = [];

    // 🔥 5 行多线程替换！（删除原 for 循环）
    const limit = pLimit(5); // 并发 5 个，JIRA 最稳定
    const promises = alarmIds.map(alarmId =>
        limit(async () => await getAlarmIssudIds(alarmId))
    );
    const results = await Promise.all(promises);
    results.forEach(issueIds => recoveriedIds.push(...issueIds));

    console.log("🎉 refreshAutoRecovery finished");
    console.log(JSON.stringify(recoveriedIds));
}

