async function refreshAssignedAlarmIssue(){
    const issues = await getAlarmAssignedIssues();
    const alarmField = IssueCustomfield['alarmId'];
    for(const issue of issues.issues){
        const alarmId = issue.fields[alarmField];
        const alert = await getAlertDetail(alarmId);

        if(alert.data.recover_state == '1'){
            const data:any = {
                "status": "PBD-CANCELED" ,
                "comment": "Alarm recovery"
            };

            await updateIssue({username:'alarm-prod'}, issue.id, data, false);

            const assigneeName = issue.fields.assignee ? issue.fields.assignee.name : "";
            if(assigneeName != ''){
                await sendAlarmAutoRecoveryMessage(issue, assigneeName)
            }
        }
    }
}


async function getCanceledIssudIds(){
    const ret:any[] = [];
    const issueList = await getRecentCanceledIssues(2000);
    if (issueList.total > 0){
        for(const issue of issueList.issues) {
            ret.push(issue.id);
        }
    }
    // 写入文件（JSON格式）
    await fs.writeFile('canceled_issues.json', JSON.stringify(ret, null, 2));
    
    console.log(ret);
    return ret;
}

// 扁平化字段以适合 CSV 格式
function flattenFields(fields: { [key: string]: any }, prefix: string = ''): { [key: string]: string } {
    const flat: { [key: string]: string } = {};
    for (const [key, value] of Object.entries(fields)) {
        const newKey = prefix ? `${prefix}.${key}` : key;
        if (value && typeof value === 'object' && !Array.isArray(value)) {
            // 处理嵌套对象
            Object.assign(flat, flattenFields(value, newKey));
        } else if (Array.isArray(value)) {
            // 处理数组，简化为逗号分隔的字符串
            flat[newKey] = value.map((item: any) => (typeof item === 'object' ? JSON.stringify(item) : item)).join('; ');
        } else {
            // 处理基本类型
            flat[newKey] = value != null ? String(value).replace(/"/g, '""') : '';
        }
    }
    return flat;
}

// 导出 Issues 到 CSV 文件，包含所有字段
async function exportIssuesToCsv(issues: any[], filePath: string): Promise<void> {
    if (issues.length === 0) {
    console.log('No issues to export.');
    return;
    }

    // 获取所有字段的唯一键
    const allFieldKeys = new Set<string>();
    issues.forEach((issue) => {
        const flatFields = flattenFields(issue.fields);
        Object.keys(flatFields).forEach((key) => allFieldKeys.add(key));
    });
    const headers = ['key', ...Array.from(allFieldKeys).sort()];

    // 转换为 CSV 行
    const rows = issues.map((issue) => {
        const flatFields = flattenFields(issue.fields);
        return headers.map((header) => {
            if (header === 'key') return `"${issue.key}"`;
            return `"${flatFields[header] || ''}"`;
        }).join(',');
    });

    // 写入 CSV 文件
    const csvContent = [headers.join(','), ...rows].join('\n');
    await fs.writeFile(filePath, csvContent, 'utf8');
    console.log(`Exported ${issues.length} issues to ${filePath}`);
}

async function getIssuesByDateRange(startDate:string, endDate:string){
    const res = await searchIssuesByDateRange(startDate, endDate, 2000);
    console.log(res)

    await exportIssuesToCsv(res.issues, './export.csv');
}

